def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.zeros_like(bins, dtype=float)
    for i in range(len(bins)):
        capacity = bins[i]
        if capacity <= 0:
            priorities[i] = np.inf
            continue
        ratio = item / capacity
        if ratio > 1:
            priorities[i] = np.inf
            continue
        score = 0
        for j in range(1, 11):
            if ratio < j * 0.1:
                score += (11 - j) * np.log(j + ratio**2 + 1)
            else:
                score += j * np.sqrt(ratio) * np.sin(ratio * j * np.pi / 2)
        if capacity % 3 == 0:
            score *= 1.15
            if ratio < 0.5:
                score += np.exp(-ratio * 5)
            else:
                score -= np.log1p(ratio * 10)
        elif capacity % 5 == 0:
            score *= 0.85
            for k in range(1, 4):
                if ratio > k * 0.2:
                    score += k * np.tanh(ratio * k)
                else:
                    score -= k * np.cos(ratio * k * np.pi)
        else:
            if ratio < 0.3:
                score *= 1.05
            else:
                score *= 0.95
            for m in range(1, 5):
                if (capacity + m) % 2 == 0:
                    score += m * np.log1p(ratio * m)
                else:
                    score -= m * np.sqrt(abs(ratio - 0.5))
        if score < 0:
            score = abs(score) * 0.5
        priorities[i] = score
    finite_priorities = priorities[np.isfinite(priorities)]
    if finite_priorities.size == 0:
        return priorities
    max_priority = np.max(finite_priorities)
    for i in range(len(priorities)):
        if not np.isfinite(priorities[i]):
            priorities[i] = max_priority * 20
    return priorities
